import { Link } from 'react-router-dom';
import { useEffect, useState } from 'react';
import Navigation from '../components/Navigation';
import Footer from '../components/Footer';

function Marquee() {
  const t = '· No menus. · No tutorials. · No app installs. · Just goals. · Just results. ';
  const r = t.repeat(8);
  return (
    <div className="marquee-wrapper" style={{ margin: '5rem 0' }}>
      <div className="marquee-track">{r}</div>
    </div>
  );
}

const features = [
  { icon: '🧠', title: 'Understands Intent', desc: 'Natural language in. Workflows out.' },
  { icon: '⚡', title: 'Generates Interfaces', desc: 'Minimal, task-specific, disposable.' },
  { icon: '✦', title: 'Learns You', desc: 'Adapts to your patterns over time.' },
  { icon: '◎', title: 'Hybrid Compute', desc: 'Local speed. Cloud reasoning.' },
];

export default function Home() {
  const [vis, setVis] = useState(false);
  useEffect(() => { setTimeout(() => setVis(true), 80); }, []);
  const fade = (delay = 0) => ({
    opacity: vis ? 1 : 0,
